 1	import React, { ComponentProps, forwardRef, HTMLProps, useState } from 'react';
 2	
 3	import { Button, ButtonVariant, Split, TextInput, TextInputProps } from '@patternfly/react-core';
 4	import { EyeIcon, EyeSlashIcon } from '@patternfly/react-icons';
 5	
 6	// PatternFly changed the signature of the 'onChange' handler for input elements.
 7	// This causes issues with React Hook Form as it expects the default signature for an input element.
 8	// So we have to create this wrapper component that takes care of converting these signatures for us.
 9	
10	export type FormPasswordInputProps = Omit<ComponentProps<typeof TextInput>, 'onChange'> &
11	  Pick<HTMLProps<HTMLInputElement>, 'onChange'>;
12	
13	export const FormPasswordInput = forwardRef<HTMLInputElement, FormPasswordInputProps>(
14	  ({ onChange, ...props }, ref) => {
15	    const [passwordHidden, setPasswordHidden] = useState(true);
16	    const onChangeForward: TextInputProps['onChange'] = (event) => onChange?.(event);
17	
18	    return (
19	      <Split>
20	        <TextInput
21	          {...props}
22	          onChange={(event, _value) => onChangeForward(event, _value)}
23	          ref={ref}
24	          type={passwordHidden ? 'password' : 'text'}
25	        />
26	        <Button onClick={() => setPasswordHidden(!passwordHidden)} variant={ButtonVariant.link}>
27	          {passwordHidden ? <EyeIcon /> : <EyeSlashIcon />}
28	        </Button>
29	      </Split>
30	    );
31	  },
32	);
33	
34	// We need to fake the displayName to match what PatternFly expects.
35	// This is because PatternFly uses it to filter children in certain aspects.
36	FormPasswordInput.displayName = 'TextInput';

